    32→import java.util.ServiceConfigurationError;
    33→import java.util.ServiceLoader;
    34→import java.util.Set;
    35→import java.util.SortedSet;
    36→import java.util.TreeSet;
    37→import java.util.function.Supplier;
    38→
    39→/**
    40→ * Superclass for plugin discovery implementations.
    41→ *
    42→ * <p>Callers of this class should use {@link #discoverPlugins(Set)} to discover plugins which are present in the
    43→ * passed-in {@link PluginSource} instances.
    44→ *
    45→ * <p>Implementors of this class should implement {@link #scanPlugins(PluginSource)}, in order to scan a single source.
    46→ * The returned {@link PluginScanResult} should contain only plugins which are loadable from the passed-in source.
    47→ * The superclass has some common functionality which is usable in subclasses, and handles merging multiple results.
    48→ *
    49→ * <p>Implementations of this class must be thread-safe, but may have side effects on the provided {@link ClassLoader}
    50→ * instances and plugin classes which may not be thread safe. This depends on the thread safety of the plugin
    51→ * implementations, due to the necessity of initializing and instantiate plugin classes to evaluate their versions.
    52→ */
    53→public abstract class PluginScanner {
    54→
    55→    private static final Logger log = LoggerFactory.getLogger(PluginScanner.class);
    56→
    57→    /**
    58→     * Entry point for plugin scanning. Discovers plugins present in any of the provided plugin sources.
    59→     * <p>See the implementation-specific documentation for the conditions for a plugin to appear in this result.
    60→     * @param sources to scan for contained plugins
    61→     * @return A {@link PluginScanResult} containing all plugins which this scanning implementation could discover.
    62→     */
    63→    public PluginScanResult discoverPlugins(Set<PluginSource> sources) {
    64→        long startMs = System.currentTimeMillis();
    65→        List<PluginScanResult> results = new ArrayList<>();
    66→        for (PluginSource source : sources) {
    67→            results.add(scanUrlsAndAddPlugins(source));
    68→        }
