    80→        log.info("Registered loader: {}", source.loader());
    81→        loadJdbcDrivers(source.loader());
    82→        return plugins;
    83→    }
    84→
    85→    /**
    86→     * Implementation-specific strategy for scanning a single {@link PluginSource}.
    87→     * @param source A single source to scan for plugins.
    88→     * @return A {@link PluginScanResult} containing all plugins which this scanning implementation could discover.
