   125→    }
   126→
   127→    @SuppressWarnings("unchecked")
   128→    protected <T> SortedSet<PluginDesc<T>> getServiceLoaderPluginDesc(PluginType type, PluginSource source) {
   129→        SortedSet<PluginDesc<T>> result = new TreeSet<>();
   130→        ServiceLoader<T> serviceLoader = ServiceLoader.load((Class<T>) type.superClass(), source.loader());
   131→        Iterator<T> iterator = serviceLoader.iterator();
   132→        while (handleLinkageError(type, source, iterator::hasNext)) {
   133→            try (LoaderSwap loaderSwap = withClassLoader(source.loader())) {
   134→                T pluginImpl;
   135→                try {
   136→                    pluginImpl = handleLinkageError(type, source, iterator::next);
   137→                } catch (ServiceConfigurationError t) {
   138→                    log.error("Failed to discover {} in {}{}",
   139→                            type.simpleName(), source, reflectiveErrorDescription(t.getCause()), t);
