   149→            }
   150→        }
   151→        return result;
   152→    }
   153→
   154→    /**
   155→     * Helper to evaluate a {@link ServiceLoader} operation while handling {@link LinkageError}s.
   156→     *
   157→     * @param type The plugin type which is being loaded
   158→     * @param function A function on a {@link ServiceLoader}'s {@link Iterator} which may throw {@link LinkageError}
   159→     * @return the return value of function
   160→     * @throws Error errors thrown by the passed-in function
   161→     * @param <U> Return value of the passed-in function
   162→     */
   163→    private <U> U handleLinkageError(PluginType type, PluginSource source, Supplier<U> function) {
   164→        // It's difficult to know for sure if the iterator was able to advance past the first broken
   165→        // plugin class, or if it will continue to fail on that broken class for any subsequent calls
   166→        // to Iterator::hasNext or Iterator::next
   167→        // For reference, see https://bugs.openjdk.org/browse/JDK-8196182, which describes
   168→        // the behavior we are trying to mitigate with this logic as buggy, but indicates that a fix
   169→        // in the JDK standard library ServiceLoader implementation is unlikely to land
   170→        LinkageError lastError = null;
   171→        // Try a fixed maximum number of times in case the ServiceLoader cannot move past a faulty plugin,
   172→        // but the LinkageError varies between calls. This limit is chosen to be higher than the typical number
   173→        // of plugins in a single plugin location, and to limit the amount of log-spam on startup.
   174→        for (int i = 0; i < 100; i++) {
   175→            try {
   176→                return function.get();
   177→            } catch (LinkageError t) {
   178→                // As an optimization, hide subsequent error logs if two consecutive errors look similar.
   179→                // This reduces log-spam for iterators which cannot advance and rethrow the same exception.
   180→                if (lastError == null
   181→                        || !Objects.equals(lastError.getClass(), t.getClass())
   182→                        || !Objects.equals(lastError.getMessage(), t.getMessage())) {
   183→                    log.error("Failed to discover {} in {}{}",
   184→                            type.simpleName(), source, reflectiveErrorDescription(t.getCause()), t);
   185→                }
   186→                lastError = t;
   187→            }
   188→        }
