   112→            }
   113→        } else {
   114→            String message = String.format(
   115→                "One or more plugins are missing ServiceLoader manifests may not be usable with %s=%s: %s%n" +
   116→                        "Read the documentation at %s for instructions on migrating your plugins " +
   117→                        "to take advantage of the performance improvements of %s mode.",
   118→                            WorkerConfig.PLUGIN_DISCOVERY_CONFIG,
   119→                    PluginDiscoveryMode.SERVICE_LOAD,
   120→                    missingPlugins.stream()
   121→                            .map(pluginDesc -> pluginDesc.location() + "\t" + pluginDesc.className() + "\t" + pluginDesc.type() + "\t" + pluginDesc.version())
   122→                            .collect(Collectors.joining("\n", "[\n", "\n]")),
   123→                    "https://kafka.apache.org/documentation.html#connect_plugindiscovery",
   124→                    PluginDiscoveryMode.SERVICE_LOAD
   125→            );
   126→            if (discoveryMode == PluginDiscoveryMode.HYBRID_WARN) {
   127→                log.warn("{} To silence this warning, set {}={} in the worker config.",
